mapper.update:
update tbl_member
set member_status = 'inactive'
where id = #{id}

mapper.select:
select v.*, case when exists ( select 1 from tbl_follow fl where fl.follower_id = #{memberId}::bigint and fl.following_id = v.id ) then true else false end as followed from vw_inquiry_member v where v.member_status = 'active' and v.id != #{memberId}::bigint
and v.category_name = #{categoryName}
limit #{criteria.count} offset #{criteria.offset}
